// Simple quorum write/read (additional snippet)
async function quorumWrite(replicas, key, value, W=2){
  const responses = await Promise.allSettled(replicas.map(r => fetch(r + '/write', {method:'POST', body: JSON.stringify({key,value})})))
  const ack = responses.filter(r => r.status === 'fulfilled' && r.value.ok).length
  if(ack < W) throw new Error('Write quorum not reached')
  return true
}

async function quorumRead(replicas, key, R=2){
  const responses = await Promise.allSettled(replicas.map(r => fetch(r + '/read?key=' + key)))
  const values = []
  for(const res of responses){
    if(res.status === 'fulfilled'){
      const body = await res.value.json()
      values.push(body)
    }
  }
  // choose latest timestamp (naive) or merge via CRDT
  return values.sort((a,b) => b.ts - a.ts)[0]
}
